ee:variables.ee:set-variable:
%dw 2.0
output application/json
---
{
	"source" : "APM" ,
	"target" : "P21",
	"integration-type" : "Inbound " ++ attributes.queryParams."type" ++ " " ++ payload[0]."b2bMessage"."header"."documentType" default payload,
	"correlationId": correlationId,
	"timestamp": now() as String {
		format: "yyyy-MM-dd'T'HH:mm:ss.SSSXXX"
	},
	"transmissionId" : payload[0].b2bMessage.header.transmissionId default ""
}

ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
  application: app.name,
  status: "success",
  timestamp: now() as String {
		format: "yyyy-MM-dd'T'HH:mm:ss.SSSXXX"
	},
  environment: Mule::p("mule.env"),
 }

